import{_ as a,H as e,f as l,i as r}from"./chunks/framework.eFU6Tutu.js";const p=JSON.parse('{"title":"Редис","description":"","frontmatter":{},"headers":[],"relativePath":"plants/radish.md","filePath":"plants/radish.md"}'),i={name:"plants/radish.md"};function n(s,t,o,d,h,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="редис" tabindex="-1">Редис <a class="header-anchor" href="#редис" aria-label="Permalink to &quot;Редис&quot;">​</a></h1><p>Редис — один из самых быстрых и благодарных овощей для выращивания на подоконнике. От всходов до сбора урожая проходит всего 20-25 дней, а свежие, хрустящие корнеплоды с лёгкой горчинкой станут приятным бонусом к зимним и весенним салатам.</p><h2 id="описание" tabindex="-1">Описание <a class="header-anchor" href="#описание" aria-label="Permalink to &quot;Описание&quot;">​</a></h2><p>Редис — однолетнее или двулетнее растение семейства Капустные, разновидность редьки посевной. В пищу употребляют корнеплод (обычно округлой или цилиндрической формы) и молодые листья. Растение холодостойкое, предпочитает прохладные условия и короткий световой день.</p><h2 id="популярные-сорта-для-дома" tabindex="-1">Популярные сорта для дома <a class="header-anchor" href="#популярные-сорта-для-дома" aria-label="Permalink to &quot;Популярные сорта для дома&quot;">​</a></h2><p>Для подоконника выбирайте скороспелые, устойчивые к цветушности (стрелкованию) сорта с компактной ботвой и округлой или короткоцилиндрической формой корнеплода.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Сорт</th><th style="text-align:left;">Характеристика</th><th style="text-align:left;">Срок созревания</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>«18 дней»</strong></td><td style="text-align:left;">Классика, цилиндрические плоды розового цвета с белым кончиком, сочная мякоть</td><td style="text-align:left;">20-25 дней</td></tr><tr><td style="text-align:left;"><strong>«Жара»</strong></td><td style="text-align:left;">Скороспелый, округлые красные плоды массой до 30 г, слабоострый вкус</td><td style="text-align:left;">18-25 дней</td></tr><tr><td style="text-align:left;"><strong>«Заря»</strong></td><td style="text-align:left;">Очень надёжный сорт, круглый, малиново-красный, хорошо переносит недостаток света</td><td style="text-align:left;">20-25 дней</td></tr><tr><td style="text-align:left;"><strong>«Французский завтрак»</strong></td><td style="text-align:left;">Красивый продолговатый редис с нежным вкусом, не грубеет при передержке</td><td style="text-align:left;">20-25 дней</td></tr><tr><td style="text-align:left;"><strong>«Кармен»</strong></td><td style="text-align:left;">Круглый, ярко-красный, сладковатый, очень вкусный, но любит прохладу</td><td style="text-align:left;">20-25 дней</td></tr><tr><td style="text-align:left;"><strong>«Дамский каприз»</strong></td><td style="text-align:left;">Скороспелый, устойчив к цветушности и засухе, корнеплод округлый, красный</td><td style="text-align:left;">20-25 дней</td></tr></tbody></table><h2 id="как-использовать-в-еде" tabindex="-1">Как использовать в еде <a class="header-anchor" href="#как-использовать-в-еде" aria-label="Permalink to &quot;Как использовать в еде&quot;">​</a></h2><ul><li>Свежие салаты (классика с огурцом и зеленью)</li><li>Окрошка</li><li>Бутерброды с маслом и редиской</li><li>Ботву редиса можно добавлять в супы и салаты</li></ul><h2 id="полезные-своиства" tabindex="-1">Полезные свойства <a class="header-anchor" href="#полезные-своиства" aria-label="Permalink to &quot;Полезные свойства&quot;">​</a></h2><ul><li>Богат витаминами С, группы В, калием и магнием</li><li>Содержит горчичные масла, стимулирующие аппетит</li><li>Низкая калорийность (около 20 ккал на 100 г)</li></ul><h2 id="уход" tabindex="-1">Уход <a class="header-anchor" href="#уход" aria-label="Permalink to &quot;Уход&quot;">​</a></h2><p><strong>Из этого раздела вы узнаете:</strong> как сеять, поливать и какой температурный режим обеспечить редису на подоконнике.</p><p><strong>Подробное руководство:</strong> <a href="/care/radish.html">Выращивание редиса на подоконнике: полное руководство</a></p><h3 id="кратко-о-главном" tabindex="-1">Кратко о главном: <a class="header-anchor" href="#кратко-о-главном" aria-label="Permalink to &quot;Кратко о главном:&quot;">​</a></h3><ul><li><strong>Прохлада — ключ к успеху:</strong> Оптимальная температура днём +16-20°C, ночью +10-15°C. Жару редис не переносит.</li><li><strong>Свет:</strong> 10-12 часов в сутки. При более длинном световом дне может уйти в стрелку (цветение) без образования корнеплода.</li><li><strong>Полив:</strong> Регулярный, почва всегда должна быть слегка влажной. При пересыхании редис становится горьким и деревянистым.</li><li><strong>Почва:</strong> Рыхлая, плодородная, нейтральной кислотности. Идеален готовый грунт для рассады.</li><li><strong>Ёмкость:</strong> Глубиной не менее 15 см.</li></ul><h2 id="источники-информации" tabindex="-1">Источники информации <a class="header-anchor" href="#источники-информации" aria-label="Permalink to &quot;Источники информации&quot;">​</a></h2><ul><li><a href="https://antonovsad.ru/vyrashchivanie-redisa-na-podokonnike-kak-priyutit-vitaminnyy-ovoshch-doma-3636/" target="_blank" rel="noreferrer">Антонов сад — Редис на подоконнике</a></li><li><a href="https://www.botanichka.ru/article/kak-vyrastit-redis-na-podokonnike-samyj-prostoj-sposob/" target="_blank" rel="noreferrer">Ботаничка — Как вырастить редис на подоконнике</a></li><li><a href="https://pogoda.mail.ru/news/62485561/" target="_blank" rel="noreferrer">Погода Mail — Редис на подоконнике</a></li></ul><h2 id="похожие-растения" tabindex="-1">Похожие растения <a class="header-anchor" href="#похожие-растения" aria-label="Permalink to &quot;Похожие растения&quot;">​</a></h2><ul><li><a href="/plants/tomatoes.html">Помидоры (черри)</a></li><li><a href="/plants/peppers.html">Перец (сладкий и острый)</a></li><li><a href="/plants/microgreens.html">Микрозелень</a></li></ul>',20)])])}const u=a(i,[["render",n]]);export{p as __pageData,u as default};
